module decoder_2to4(
    input en,         // Enable signal.
    input [1:0] a,    // 2-bit binary input.
    output [3:0] y    // 4-bit one-hot output.
);

reg [3:0] z_q;

// Decoder logic
always @(*) begin
    if (en) begin
        case (a)
            2'b00: z_q = 4'b0001;
            2'b01: z_q = 4'b0010;
            2'b10: z_q = 4'b0100;
            2'b11: z_q = 4'b1000;
            default: z_q = 4'b0000;
        endcase
    end else begin
        z_q = 4'b0000;
    end
end

assign y = z_q;

endmodule
